import 'bootstrap/dist/css/bootstrap.min.css';
import './css/home.css'

import githubLogo from './img/logos/github-mark-white.png'
import linkedinLogo from './img/logos/in-logo-white.png'
import twitterLogo from './img/logos/twitter-128.png'
import photo from './img/gatito.jpg'

export default function Home(){
    return (
        <div className="Home">
                <section className='main-page' id='main-page-id'>
                    <div className='container d-flex align-items-center justify-content-center'>
                        <div className='text-main-page text-center  '>
                            <div className='col-md-12'>
                                {/*PROFILE PICTURE WILL BE SHOWN
                                <div className='pfp-span'><img  className='pfp' src={photo} width={200} height={200} alt='pfp-photo'/></div>
                                */}
                                <p className='name'>Jorge <span className='name-p1'>Alexis</span> <span className='name-p1'>M</span>árquez <span className='name-p1'>Rosales</span></p>  
                            </div>
                            <div className='container text-center main-text'>
                                <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Morbi faucibus ut dui commodo aliquam. Duis non ipsum posuere, viverra lorem pellentesque, semper elit. Proin pellentesque, mi</p>
                            </div>
                            <div className='col-md-12'>
                                <div className='col-md-12'>
                                    <button className='info-btn'>Check my resume</button>
                                </div>
                            </div>
                            <div className='col-md-12 sm-all'>
                                <div className='row'>
                                    <div className='col-md-4 col-4'><a href=""><img src={twitterLogo} width={31} height={31} className="d-inline-block align-top" alt="github.com/alexismrosales"/></a></div>
                                    <div className='col-md-4 col-4'><a href="https://github.com/alexismrosales"><img src={githubLogo} width={31} height={31} className="d-inline-block align-top" alt="github.com/alexismrosales"/></a></div>
                                    <div className='col-md-4 col-4'><a href="https://www.linkedin.com/in/alexismrosales/"><img src={linkedinLogo} width={35} height={35} className="d-inline-block align-top" alt="linkedin.com/in/alexismrosales/"/></a></div>      
                                </div>  
                            </div>
                        </div>
                    </div>
                </section>
                <section className='projects-page'>
                    <div className='container'>
                        <div className='row'>
                            <div className='col-md-12'>

                            </div>
                        </div>
                    </div>
                </section>
        </div>
    )
}

window.addEventListener('scroll', function() {
    var nav = document.querySelector('.nav');
    var section = document.querySelector('#main-page-id');
    if (window.scrollY >= section.offsetTop + section.offsetHeight) {
      nav.classList.add('shadow');
    } else {
      nav.classList.remove('shadow');
    }
});
